```class Solution {
public:
    int lengthAfterTransformations(string s, int t, vector<int>& nums) {
        int res = s.size();
        for (int i = 0; i < t; i++) {
            string temp = "";
            for (char c : s) {
                int idx = c - 'a';
                for (int j = 0; j < nums[idx]; j++) {
                    temp += (char)(idx + 'a' + j % 26);
                }
            }
            s = temp;
            res = min(res, (int)s.size());
        }
        return res % (1e9 + 7);
    }
};```
